/* ==================== FUENTE GLOBAL ZURICHSANS ==================== */
/* Regular */
@font-face {
  font-family: "ZurichSans";
  src:
    /* Usa WOFF2 si lo tienes hospedado; si no, deja solo el TTF */
    /* url("https://bpm.beesmart.ec/fonts/zurich/ZurichSans-Regular.woff2") format("woff2"), */
    url("https://bpm.beesmart.ec/fonts/zurich/ZurichSans-Regular.ttf") format("truetype");
  font-weight: 400;
  font-style: normal;
  font-display: swap;
}

/* Bold (opcional: comenta si no existe el archivo) */
@font-face {
  font-family: "ZurichSans";
  src:
    /* url("https://bpm.beesmart.ec/fonts/zurich/ZurichSans-Bold.woff2") format("woff2"), */
    url("https://bpm.beesmart.ec/fonts/zurich/ZurichSans-Bold.ttf") format("truetype");
  font-weight: 700;
  font-style: normal;
  font-display: swap;
}

/* Aplicar a absolutamente todo (incluye pseudo-elementos) */
:where(html, body) {
  font-family: "ZurichSans", Arial, sans-serif !important;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}
:where(*, *::before, *::after) {
  font-family: inherit !important;
}

/* Controles de formulario (algunos navegadores fuerzan UI fonts) */
:where(input, textarea, select, button, optgroup, option) {
  font-family: inherit !important;
}

/* Texto dentro de SVG (si renderizas iconos/labels como texto) */
svg text {
  font-family: inherit !important;
}

/* Impresión / exportar a PDF del navegador */
@media print {
  :where(html, body, *) {
    font-family: "ZurichSans", Arial, sans-serif !important;
  }
}

/* ==================== TU CSS (queda igual) ==================== */

/* Forzado absoluto (ya lo hacemos más arriba, puedes dejarlo si gustas) */
html, body, :where(*) {
  font-family: 'ZurichSans', Arial, sans-serif !important;
}

/* ======= ENCABEZADO (logo) ======= */
[selector = 'encabezado'] {
  display: flex;
  justify-content: flex-end;
  align-items: center;
  padding-top: 4px;
}
[selector = 'encabezado'] img {
  position: static;
  height: 120px;
  width: auto;
  margin-top: -15px;
  margin-right: 320px;
}

[selector = "slip-titulo"] p,
[selector = "slip-subtitulo"] p,
[selector = "slip-titulo-margen"] {
  text-align: center;
  font-size: 20px;
  color: #2167AE;
  font-weight: 700;
}
[selector = "slip-subtitulo"] p{ margin-top: -20px; }
[selector = "slip-titulo-margen"]{ margin-top: 40px; margin-bottom: 10px; }

[selector = "parrafo-slip"] {
  font-size: 18px;
  color: #111111;
  text-align: justify;
  line-height: 1.5;
}

[selector = "parrafo-slip"] p {
  font-size: 18px;
  margin: 10px 0;
  color: #111111;
  text-align: justify;
}

[selector = "parrafo-slip"] ul {
  margin: 8px 0 12px 24px;
  padding: 0;
  list-style-type: circle;
  text-align: justify;
  font-size: 18px;
}

[selector = "parrafo-slip"] ul ul {
  margin: 6px 0 6px 20px;
  list-style-type: square;
  text-align: justify;
  font-size: 18px;
}

[selector = "parrafo-slip"] li {
  margin-bottom: 6px;
  line-height: 1.4;
  text-align: justify;
  font-size: 18px;
}

[selector = "parrafo-slip"] li strong {
  display: inline-block;
  margin-bottom: 4px;
  font-size: 18px;
  color: #111111;
  text-transform: uppercase;
  letter-spacing: .5px;
  text-align: justify;
}

/* ======= PAGE BREAK ======= */
[selector = 'page-break'] {
  page-break-before: always;
  break-before: page;
  display: block;
  height: 0;
}

/* ======= CONFIGURACIÓN DE PÁGINA ======= */
@page {
  margin-top: 84px;
  margin-bottom: 84px;
}
